approaches.code_python:
def mySqrt(x: int) -> int:
    if x < 0:
        return -1  # Invalid input for negative numbers
    if x == 0 or x == 1:
        return x
    for i in range(x + 1):
        if i * i > x:
            return i - 1
    return 0

