approaches.code_java:
class Solution {
    public int mySqrt(int x) {
        if (x < 2) return x;
        int low = 0, high = x, mid;
        while (low <= high) {
            mid = low + (high - low) / 2;
            long midSquared = (long) mid * mid;
            if (midSquared == x) {
                return mid;
            } else if (midSquared < x) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return high;
    }
}

