approaches.code_javascript:
function mySqrt(x) {
    if (x < 0) return -1; // Handle negative input
    if (x === 0 || x === 1) return x; // Handle 0 and 1

    let low = 0, high = x, result = 0;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const midSquared = mid * mid;

        if (midSquared === x) {
            return mid;
        } else if (midSquared < x) {
            result = mid; // Update result to mid
            low = mid + 1; // Search in the right half
        } else {
            high = mid - 1; // Search in the left half
        }
    }

    return result; // Return the largest integer whose square is less than or equal to x
}

